# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory system that coordinates users, projects, tasks,
messaging, performance metrics, and reporting. The public surface is exercised
by ``test_solution.py``.

Design notes
------------
* A single re-entrant lock is shared by the manager and every sub-store so that
  all mutations are serialized and the per-store ``_lock`` attributes are
  identical objects (required by the concurrency tests).
* Identifiers for users, projects, tasks, and messages are drawn from one
  global counter, guaranteeing they are unique across entity types.
* All getters return deep copies so callers can never mutate internal state by
  holding on to a returned object or list.
"""

import collections
import copy
import csv
import enum
import io
import threading
from datetime import datetime
from typing import Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(enum.Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(enum.Enum):
    """Roles a user may hold."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(enum.Enum):
    """Supported export formats."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    """Kinds of reports the manager can generate."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Data records (mutable; getters return copies)
# ---------------------------------------------------------------------------
class Attachment:
    """A file attached to a message."""

    __slots__ = ("filename", "size", "uploaded_by", "uploaded_at")

    def __init__(self, filename, size, uploaded_by, uploaded_at):
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at

    def __repr__(self):
        return "Attachment(filename={0!r}, size={1})".format(
            self.filename, self.size
        )


class User:
    """A registered user."""

    __slots__ = ("id", "username", "email", "role", "created_at")

    def __init__(self, id, username, email, role, created_at):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at

    def __repr__(self):
        return "User(id={0}, username={1!r})".format(self.id, self.username)


class Project:
    """A project owned by a user."""

    __slots__ = (
        "id",
        "name",
        "start_date",
        "end_date",
        "owner_id",
        "description",
    )

    def __init__(self, id, name, start_date, end_date, owner_id, description=""):
        self.id = id
        self.name = name
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id
        self.description = description

    def __repr__(self):
        return "Project(id={0}, name={1!r})".format(self.id, self.name)


class Task:
    """A unit of work inside a project."""

    __slots__ = (
        "id",
        "project_id",
        "title",
        "status",
        "assignee_id",
        "deadline",
        "started_at",
        "completed_at",
        "created_at",
    )

    def __init__(
        self,
        id,
        project_id,
        title,
        status=TaskStatus.NOT_STARTED,
        assignee_id=None,
        deadline=None,
        started_at=None,
        completed_at=None,
        created_at=None,
    ):
        self.id = id
        self.project_id = project_id
        self.title = title
        self.status = status
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.started_at = started_at
        self.completed_at = completed_at
        self.created_at = created_at

    def __repr__(self):
        return "Task(id={0}, title={1!r}, status={2})".format(
            self.id, self.title, self.status.value
        )


class Message:
    """A message posted to a project or a task."""

    __slots__ = (
        "id",
        "author_id",
        "body",
        "project_id",
        "task_id",
        "parent_id",
        "attachments",
        "created_at",
        "edited_at",
    )

    def __init__(
        self,
        id,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
        created_at=None,
        edited_at=None,
    ):
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = attachments if attachments is not None else []
        self.created_at = created_at
        self.edited_at = edited_at

    def __repr__(self):
        return "Message(id={0}, author_id={1})".format(self.id, self.author_id)


class Rating:
    """A peer rating left for a user."""

    __slots__ = (
        "id",
        "rater_id",
        "ratee_id",
        "score",
        "feedback",
        "task_id",
        "created_at",
    )

    def __init__(
        self,
        id,
        rater_id,
        ratee_id,
        score,
        feedback="",
        task_id=None,
        created_at=None,
    ):
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at

    def __repr__(self):
        return "Rating(id={0}, ratee_id={1}, score={2})".format(
            self.id, self.ratee_id, self.score
        )


# ---------------------------------------------------------------------------
# Internal storage
# ---------------------------------------------------------------------------
class _Store:
    """A simple keyed collection that shares a lock with its manager."""

    __slots__ = ("_lock", "_items")

    def __init__(self, lock):
        self._lock = lock
        self._items = {}


_UNSET = object()


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates users, projects, tasks, messaging, and reporting."""

    def __init__(self, now=None):
        # A single re-entrant lock shared across every sub-store.
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now

        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)
        self.reports = _Store(self._lock)

        # Secondary indexes.
        self._tasks_by_assignee = collections.defaultdict(set)
        self._ratings_by_ratee = collections.defaultdict(list)

        self._id_counter = 0
        self._rating_counter = 0

    # -- internal helpers --------------------------------------------------
    def _next_id(self):
        self._id_counter += 1
        return self._id_counter

    def _next_rating_id(self):
        self._rating_counter += 1
        return self._rating_counter

    @staticmethod
    def _clone(obj):
        return copy.deepcopy(obj)

    @staticmethod
    def _clone_list(items):
        return [copy.deepcopy(item) for item in items]

    def _require_user(self, user_id):
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages._items.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    @staticmethod
    def _validate_email(email):
        if not isinstance(email, str):
            raise ValidationError("Email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("Invalid email address")
        return cleaned

    @staticmethod
    def _completion_seconds(task):
        if task.started_at is not None and task.completed_at is not None:
            return (task.completed_at - task.started_at).total_seconds()
        return None

    # -- user management ---------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if not isinstance(username, str) or not username.strip():
                raise ValidationError("Username must be a non-empty string")
            username = username.strip()
            email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            for existing in self.users._items.values():
                if existing.username == username:
                    raise DuplicateError(
                        "Username {0!r} already exists".format(username)
                    )
                if existing.email == email:
                    raise DuplicateError(
                        "Email {0!r} already exists".format(email)
                    )

            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users._items[user.id] = user
            return self._clone(user)

    def get_user(self, user_id):
        with self._lock:
            return self._clone(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            users = [self.users._items[k] for k in sorted(self.users._items)]
            return self._clone_list(users)

    def update_user(self, user_id, username=_UNSET, email=_UNSET, role=_UNSET):
        with self._lock:
            user = self._require_user(user_id)

            if username is not _UNSET:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("Username must be a non-empty string")
                username = username.strip()
                for other in self.users._items.values():
                    if other.id != user_id and other.username == username:
                        raise DuplicateError(
                            "Username {0!r} already exists".format(username)
                        )

            if email is not _UNSET:
                email = self._validate_email(email)
                for other in self.users._items.values():
                    if other.id != user_id and other.email == email:
                        raise DuplicateError(
                            "Email {0!r} already exists".format(email)
                        )

            if role is not _UNSET and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not _UNSET:
                user.username = username
            if email is not _UNSET:
                user.email = email
            if role is not _UNSET:
                user.role = role

            return self._clone(user)

    def delete_user(self, user_id):
        with self._lock:
            self._require_user(user_id)

            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "User {0} owns a project".format(user_id)
                    )

            for task_id in self._tasks_by_assignee.get(user_id, set()):
                task = self.tasks._items.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError(
                        "User {0} has an open task".format(user_id)
                    )

            self._tasks_by_assignee.pop(user_id, None)
            del self.users._items[user_id]

    # -- project management ------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("Project name must be a non-empty string")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")
            self._require_user(owner_id)

            project = Project(
                id=self._next_id(),
                name=name.strip(),
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description,
            )
            self.projects._items[project.id] = project
            return self._clone(project)

    def get_project(self, project_id):
        with self._lock:
            return self._clone(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            projects = [
                self.projects._items[k] for k in sorted(self.projects._items)
            ]
            return self._clone_list(projects)

    def update_project(
        self,
        project_id,
        name=_UNSET,
        start_date=_UNSET,
        end_date=_UNSET,
        description=_UNSET,
    ):
        with self._lock:
            project = self._require_project(project_id)

            if name is not _UNSET:
                if not isinstance(name, str) or not name.strip():
                    raise ValidationError(
                        "Project name must be a non-empty string"
                    )

            new_start = project.start_date if start_date is _UNSET else start_date
            new_end = project.end_date if end_date is _UNSET else end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")

            if name is not _UNSET:
                project.name = name.strip()
            if start_date is not _UNSET:
                project.start_date = start_date
            if end_date is not _UNSET:
                project.end_date = end_date
            if description is not _UNSET:
                project.description = description

            return self._clone(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)

            task_ids = [
                tid
                for tid, task in self.tasks._items.items()
                if task.project_id == project_id
            ]
            for tid in task_ids:
                task = self.tasks._items.pop(tid)
                if task.assignee_id is not None:
                    self._tasks_by_assignee[task.assignee_id].discard(tid)

            task_id_set = set(task_ids)
            message_ids = [
                mid
                for mid, msg in self.messages._items.items()
                if msg.project_id == project_id or msg.task_id in task_id_set
            ]
            for mid in message_ids:
                del self.messages._items[mid]

            del self.projects._items[project_id]

    # -- task management ---------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("Task title must be a non-empty string")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError(
                    "deadline cannot precede the project start date"
                )

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._now(),
            )
            self.tasks._items[task.id] = task
            if assignee_id is not None:
                self._tasks_by_assignee[assignee_id].add(task.id)
            return self._clone(task)

    def get_task(self, task_id):
        with self._lock:
            return self._clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = [
                self.tasks._items[k]
                for k in sorted(self.tasks._items)
                if self.tasks._items[k].project_id == project_id
            ]
            return self._clone_list(tasks)

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            self._require_user(assignee_id)
            ids = sorted(self._tasks_by_assignee.get(assignee_id, set()))
            tasks = [self.tasks._items[tid] for tid in ids]
            return self._clone_list(tasks)

    def _set_assignee(self, task, new_assignee_id):
        if task.assignee_id is not None:
            self._tasks_by_assignee[task.assignee_id].discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self._tasks_by_assignee[new_assignee_id].add(task.id)

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return self._clone(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return self._clone(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return self._clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError(
                        "deadline cannot precede the project start date"
                    )
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None

            task.status = status
            return self._clone(task)

    # -- messaging ---------------------------------------------------------
    def _build_attachments(self, specs, author_id):
        attachments = []
        now = self._now()
        for filename, data in specs:
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("Attachment filename must be non-empty")
            attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
            )
        return attachments

    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ):
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "Exactly one of project_id or task_id is required"
                )

            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            built_attachments = self._build_attachments(
                attachments or [], author_id
            )

            if (not isinstance(body, str) or not body.strip()) and not built_attachments:
                raise ValidationError(
                    "Message body is required when there are no attachments"
                )

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built_attachments,
                created_at=self._now(),
            )
            self.messages._items[message.id] = message
            return self._clone(message)

    def edit_message(self, message_id, author_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != author_id:
                raise AuthorizationError(
                    "Only the author may edit this message"
                )
            empty = not isinstance(new_body, str) or not new_body.strip()
            if empty and not message.attachments:
                raise ValidationError(
                    "Message body is required when there are no attachments"
                )
            message.body = new_body
            message.edited_at = self._now()
            return self._clone(message)

    def add_attachment(self, message_id, author_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != author_id:
                raise AuthorizationError(
                    "Only the author may attach to this message"
                )
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("Attachment filename must be non-empty")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=self._now(),
                )
            )
            return self._clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            messages = [
                self.messages._items[k]
                for k in sorted(self.messages._items)
                if self.messages._items[k].project_id == project_id
            ]
            return self._clone_list(messages)

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            messages = [
                self.messages._items[k]
                for k in sorted(self.messages._items)
                if self.messages._items[k].task_id == task_id
            ]
            return self._clone_list(messages)

    def delete_message(self, message_id, author_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != author_id:
                raise AuthorizationError(
                    "Only the author may delete this message"
                )
            del self.messages._items[message_id]

    # -- performance dashboard ---------------------------------------------
    def _tasks_for_user(self, user_id):
        ids = self._tasks_by_assignee.get(user_id, set())
        return [self.tasks._items[tid] for tid in ids if tid in self.tasks._items]

    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_user(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            durations = [
                self._completion_seconds(t)
                for t in self._tasks_for_user(user_id)
                if t.status == TaskStatus.COMPLETED
            ]
            durations = [d for d in durations if d is not None]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("Users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_rating_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._now(),
            )
            self._ratings_by_ratee[ratee_id].append(rating)
            return self._clone(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_by_ratee.get(user_id, [])
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": self._clone_list(ratings),
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_user(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0

            durations = [
                self._completion_seconds(t)
                for t in tasks
                if t.status == TaskStatus.COMPLETED
            ]
            durations = [d for d in durations if d is not None]
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )

            ratings = self._ratings_by_ratee.get(user_id, [])
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # -- reports -----------------------------------------------------------
    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = [
                t
                for t in self.tasks._items.values()
                if t.project_id == project_id
            ]
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            completed = 0
            overdue = 0
            per_assignee = {}
            now = self._now()

            for task in tasks:
                status_counts[task.status.value] += 1
                is_completed = task.status == TaskStatus.COMPLETED
                if is_completed:
                    completed += 1
                if (
                    task.deadline is not None
                    and not is_completed
                    and task.deadline < now
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id, {"total": 0, "completed": 0}
                    )
                    bucket["total"] += 1
                    if is_completed:
                        bucket["completed"] += 1

            completion_rate = completed / total if total else 0.0
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def _user_task_stats(self, tasks):
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        completion_rate = completed / total if total else 0.0
        durations = [
            self._completion_seconds(t)
            for t in tasks
            if t.status == TaskStatus.COMPLETED
        ]
        durations = [d for d in durations if d is not None]
        average = sum(durations) / len(durations) if durations else None
        return total, completed, completion_rate, average

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                tasks = [
                    t
                    for t in self.tasks._items.values()
                    if t.project_id == project_id
                ]
            else:
                tasks = list(self.tasks._items.values())

            assignees = sorted(
                {t.assignee_id for t in tasks if t.assignee_id is not None}
            )
            rows = []
            for uid in assignees:
                user_tasks = [t for t in tasks if t.assignee_id == uid]
                total, completed, rate, average = self._user_task_stats(
                    user_tasks
                )
                rows.append(
                    {
                        "user_id": uid,
                        "total_tasks": total,
                        "completed_tasks": completed,
                        "completion_rate": rate,
                        "average_completion_time": average,
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ids = sorted(self._tasks_by_assignee.get(user_id, set()))
            tasks = [self.tasks._items[tid] for tid in ids]
            total, completed, rate, average = self._user_task_stats(tasks)
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": rate,
                "average_completion_time": average,
                "tasks": self._clone_list(tasks),
            }

    # -- report export -----------------------------------------------------
    def export_report(self, report, fmt):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if fmt == ReportFormat.CSV:
            return self._report_to_csv(report)
        if fmt == ReportFormat.PDF:
            return self._report_to_pdf(report)
        raise ValidationError("Unsupported report format")

    @staticmethod
    def _report_to_csv(report):
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")
        if isinstance(rows, list) and rows:
            headers = list(rows[0].keys())
            writer.writerow(headers)
            for row in rows:
                writer.writerow(["" if row.get(h) is None else row.get(h) for h in headers])
        else:
            scalar = [
                (k, v)
                for k, v in report.items()
                if not isinstance(v, (list, dict))
            ]
            if not scalar:
                scalar = [("report", report.get("report_type", "report"))]
            writer.writerow([k for k, _ in scalar])
            writer.writerow(["" if v is None else v for _, v in scalar])
        return output.getvalue()

    def _report_to_pdf(self, report):
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            lines.append("{0}: {1}".format(key, value))
        return self._build_pdf(lines)

    @staticmethod
    def _build_pdf(lines):
        def escape(text):
            return (
                text.replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )

        content = "BT\n/F1 12 Tf\n50 750 Td\n14 TL\n"
        for index, line in enumerate(lines):
            prefix = "" if index == 0 else "T*\n"
            content += "{0}({1}) Tj\n".format(prefix, escape(str(line)))
        content += "ET"
        content_bytes = content.encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>",
            b"<< /Length "
            + str(len(content_bytes)).encode("ascii")
            + b" >>\nstream\n"
            + content_bytes
            + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets = []
        for number, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += "{0} 0 obj\n".format(number).encode("ascii")
            pdf += body
            pdf += b"\nendobj\n"

        xref_pos = len(pdf)
        size = len(objects) + 1
        pdf += "xref\n0 {0}\n".format(size).encode("ascii")
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += "<< /Size {0} /Root 1 0 R >>\n".format(size).encode("ascii")
        pdf += b"startxref\n"
        pdf += "{0}\n".format(xref_pos).encode("ascii")
        pdf += b"%%EOF"
        return bytes(pdf)


